// Parameter x must be const to use it in post()
int abs_val(const int x)
    post(r: r >= 0)
{ return x < 0 ? -x : x; }

// The result name in post() is arbitrary
double ratio(const int numerator, const int denominator)
    pre(denominator != 0)
    post(result: result > -1000.0 && result < 1000.0)
{ return static_cast<double>(numerator) / denominator; }

