    printf("[handler] predicate: \"%s\"\n", v.comment());
    printf("[handler] location:  %s:%u\n", v.location().file_name(), v.location().line());
    printf("[handler] semantic:  %d (enforce=3)\n", static_cast<int>(v.semantic()));
