#include <cstdio>

void handle_contract_violation(const std::contracts::contract_violation& v) {
    // Определяем вид и семантику по числовому значению
    const char* kind_str =
        (static_cast<int>(v.kind()) == 1) ? "pre"  :
        (static_cast<int>(v.kind()) == 2) ? "post" : "assert";
    const char* sem_str =
        (static_cast<int>(v.semantic()) == 2) ? "observe" : "enforce";
    std::printf("[%s/%s] \"%s\"\n", kind_str, sem_str, v.comment());
    std::fflush(stdout);
