#include <contracts>
#include <cstdio>

void handle_contract_violation(const std::contracts::contract_violation& v) {
    const char* kind_str =
        (static_cast<int>(v.kind()) == 1) ? "pre"  :
        (static_cast<int>(v.kind()) == 2) ? "post" : "assert";
    printf("[%s] \"%s\"\n", kind_str, v.comment());
    fflush(stdout);
    // observe mode: return, execution continues
}

struct Stack {
    static constexpr int CAP = 4;
    int data[CAP] = {};
    int sz = 0;

    bool empty() const { return sz == 0; }
    bool full()  const { return sz == CAP; }
    int  size()  const { return sz; }

    void push(int v)
        pre(!full())
    {
        data[sz++] = v;
        contract_assert(sz > 0 && sz <= CAP);
    }

    int pop()
        pre(!empty())
    {
        return data[--sz];
    }

    int top() const
        pre(!empty())
    {
        return data[sz - 1];
    }
};

int main() {
    Stack s;
    s.push(1);
    s.push(2);
    s.push(3);

    printf("size=%d top=%d\n", s.size(), s.top());
    printf("pop=%d\n", s.pop());
    printf("pop=%d\n", s.pop());
    printf("size=%d\n", s.size());

    Stack empty_s;
    int v = empty_s.top();    // pre(!empty()) violated
    printf("top of empty (observe): %d\n", v);

    contract_assert(s.size() >= 0);   // true
    contract_assert(s.size() > 10);   // false — logged
    printf("done\n");
}
