// Старый стиль: assert() — отключается через -DNDEBUG
int old_sqrt(const int x) {
    assert(x >= 0);  // в release-сборке с NDEBUG исчезает без следа
    int r = 0;
    while ((r + 1) * (r + 1) <= x) ++r;
    return r;
}

// Новый стиль: pre() — поведение управляется семантикой вычисления
int new_sqrt(const int x)
    pre(x >= 0)
{
    int r = 0;
    while ((r + 1) * (r + 1) <= x) ++r;
    return r;
}

int main() {
    // Оба работают одинаково при корректном вводе
    std::printf("old_sqrt(25) = %d\n", old_sqrt(25));
    std::printf("new_sqrt(25) = %d\n", new_sqrt(25));
    std::printf("old_sqrt(16) = %d\n", old_sqrt(16));
    std::printf("new_sqrt(16) = %d\n", new_sqrt(16));

    // Нарушение: pre() вызывает обработчик нарушения контракта
    new_sqrt(-1);
}

