// УЗКИЙ контракт: работает только для x > 0.
// Вызывающая сторона обязана гарантировать ввод.
double log_narrow(const double x)
    pre(x > 0.0)
{
    return x * 2.5;  // упрощено для примера
}

// ШИРОКИЙ контракт: обрабатывает любой ввод, включая некорректный.
// Нет предусловий — функция сама является частью обработки ошибок.
double log_wide(const double x) {
    if (x <= 0.0) {
        std::printf("[log_wide] invalid input %.1f, returning -1\n", x);
        return -1.0;
    }
    return x * 2.5;
}

int main() {
    // Узкий: корректный ввод
    std::printf("log_narrow(4.0) = %.1f\n", log_narrow(4.0));
    std::printf("log_narrow(1.0) = %.1f\n", log_narrow(1.0));

    // Широкий: любой ввод
    std::printf("log_wide(4.0)   = %.1f\n", log_wide(4.0));
    std::printf("log_wide(-1.0)  = %.1f\n", log_wide(-1.0));

    // Узкий с нарушением: pre() срабатывает
    std::printf("calling log_narrow(-1.0)...\n");
    log_narrow(-1.0);
    std::printf("unreachable\n");
}

