    std::printf("correct: ");
    setup_buffer_correct(config_value);

    // Неверная версия: контракт срабатывает — программа падает из-за конфига
    std::printf("wrong: ");
    setup_buffer_wrong(config_value);
    std::printf("unreachable\n");
