// Бинарный поиск с contract_assert для инвариантов алгоритма.
// Unit-тест проверяет результат на конкретных данных;
// contract_assert проверяет инвариант при каждом вызове в QA-прогоне.
int binary_search(const int* arr, const int n, const int target)
    pre(arr != nullptr)
    pre(n > 0)
    post(r: r >= -1 && r < n)
{
    int lo = 0, hi = n - 1;
    while (lo <= hi) {
        const int mid = lo + (hi - lo) / 2;
        contract_assert(mid >= 0 && mid < n);  // инвариант: mid остаётся в [0,n)

        if (arr[mid] == target) return mid;
        if (arr[mid] < target) lo = mid + 1;
        else                   hi = mid - 1;
    }
    return -1;
}

int main() {
    const int data[] = {1, 3, 5, 7, 9, 11, 13};
    const int n = 7;

    std::printf("search(7)  = index %d\n", binary_search(data, n, 7));
    std::printf("search(1)  = index %d\n", binary_search(data, n, 1));
    std::printf("search(13) = index %d\n", binary_search(data, n, 13));
    std::printf("search(6)  = index %d\n", binary_search(data, n, 6));

    // pre() ловит программную ошибку (передача n=0) прямо на месте вызова
    std::printf("calling binary_search with n=0...\n");
    binary_search(data, 0, 7);
    std::printf("unreachable\n");
}

